import { useState, useCallback } from 'react';
import { User, UserRole } from '../types';

// ── Mock role assignment ──────────────────────────────────────────────────────
// In production this would come from your auth provider / backend.
// For now: specific emails → admin, everyone else → participant.

const ADMIN_EMAILS = [
  'admin@formthread.io',
  'riya@formthread.io',
  'creator@formthread.io',
];

// Participant → form assignment map (mock)
const PARTICIPANT_FORM_MAP: Record<string, string[]> = {
  'arjun@nexaralabs.com':   ['form-1'],
  'sara@lind-studio.com':   ['form-2'],
  'devraj@gmail.com':       ['form-3'],
};

const STORAGE_KEY = 'formthread_user';

function buildUser(email: string): User {
  const normalised = email.toLowerCase().trim();
  const role: UserRole = ADMIN_EMAILS.includes(normalised) ? 'admin' : 'participant';
  const namePart = normalised.split('@')[0];
  const name = namePart.charAt(0).toUpperCase() + namePart.slice(1).replace(/[._-]/g, ' ');
  const initial = name[0].toUpperCase();
  const assignedFormIds = PARTICIPANT_FORM_MAP[normalised] ?? ['form-1'];

  return { email: normalised, name, role, initial, assignedFormIds };
}

// ── Hook ──────────────────────────────────────────────────────────────────────

export function useUser() {
  const [user, setUser] = useState<User | null>(() => {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      return raw ? (JSON.parse(raw) as User) : null;
    } catch {
      return null;
    }
  });

  const login = useCallback((email: string) => {
    const newUser = buildUser(email);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newUser));
    setUser(newUser);
    return newUser;
  }, []);

  const logout = useCallback(() => {
    localStorage.removeItem(STORAGE_KEY);
    setUser(null);
  }, []);

  return { user, login, logout, isAdmin: user?.role === 'admin' };
}
